import React, { useState, useEffect, useCallback } from 'react';
import { productAPI } from '../../services/api';
import Pagination from '../../components/ui/Pagination';
import toast from 'react-hot-toast';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import AddIcon from '@mui/icons-material/Add';

const EMPTY_PRODUCT = {
  name: '', description: '', shortDescription: '', basePrice: '',
  category: 'green-tea', origin: '', thumbnail: '', caffeineLevel: 'medium',
  brewingTime: '', temperature: '', isFeatured: false, flavor: '', tags: '',
};

const CATEGORIES = ['green-tea','black-tea','herbal-tea','oolong-tea','white-tea','chai','matcha'];
const CAFFEINE = ['none','low','medium','high'];

const ProductFormModal = ({ product, onClose, onSave }) => {
  const [form, setForm] = useState(product ? {
    ...product,
    flavor: product.flavor?.join(', ') || '',
    tags: product.tags?.join(', ') || '',
  } : EMPTY_PRODUCT);
  const [saving, setSaving] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm({ ...form, [name]: type === 'checkbox' ? checked : value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    const payload = {
      ...form,
      basePrice: parseFloat(form.basePrice),
      flavor: form.flavor.split(',').map((f) => f.trim()).filter(Boolean),
      tags: form.tags.split(',').map((t) => t.trim()).filter(Boolean),
    };
    try {
      if (product?._id) {
        await productAPI.update(product._id, payload);
        toast.success('Product updated!');
      } else {
        await productAPI.create(payload);
        toast.success('Product created!');
      }
      onSave();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center p-4 pt-16 overflow-y-auto">
      <div className="fixed inset-0 bg-black/50" onClick={onClose} />
      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-2xl z-10 p-6">
        <h2 className="font-display text-xl text-tea-900 mb-5">{product ? 'Edit Product' : 'New Product'}</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className="text-xs font-medium text-gray-600 mb-1 block">Product Name *</label>
              <input name="name" value={form.name} onChange={handleChange} required className="input" />
            </div>
            <div>
              <label className="text-xs font-medium text-gray-600 mb-1 block">Category *</label>
              <select name="category" value={form.category} onChange={handleChange} className="input">
                {CATEGORIES.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div>
              <label className="text-xs font-medium text-gray-600 mb-1 block">Base Price ($) *</label>
              <input name="basePrice" type="number" step="0.01" min="0" value={form.basePrice} onChange={handleChange} required className="input" />
            </div>
            <div className="col-span-2">
              <label className="text-xs font-medium text-gray-600 mb-1 block">Short Description</label>
              <input name="shortDescription" value={form.shortDescription} onChange={handleChange} className="input" />
            </div>
            <div className="col-span-2">
              <label className="text-xs font-medium text-gray-600 mb-1 block">Description *</label>
              <textarea name="description" value={form.description} onChange={handleChange} required rows={3} className="input resize-none" />
            </div>
            <div>
              <label className="text-xs font-medium text-gray-600 mb-1 block">Origin</label>
              <input name="origin" value={form.origin} onChange={handleChange} className="input" placeholder="Darjeeling, India" />
            </div>
            <div>
              <label className="text-xs font-medium text-gray-600 mb-1 block">Caffeine Level</label>
              <select name="caffeineLevel" value={form.caffeineLevel} onChange={handleChange} className="input">
                {CAFFEINE.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div>
              <label className="text-xs font-medium text-gray-600 mb-1 block">Brewing Time</label>
              <input name="brewingTime" value={form.brewingTime} onChange={handleChange} className="input" placeholder="3-4 minutes" />
            </div>
            <div>
              <label className="text-xs font-medium text-gray-600 mb-1 block">Temperature</label>
              <input name="temperature" value={form.temperature} onChange={handleChange} className="input" placeholder="90°C" />
            </div>
            <div className="col-span-2">
              <label className="text-xs font-medium text-gray-600 mb-1 block">Thumbnail URL</label>
              <input name="thumbnail" value={form.thumbnail} onChange={handleChange} className="input" placeholder="https://..." />
            </div>
            <div className="col-span-2">
              <label className="text-xs font-medium text-gray-600 mb-1 block">Flavour Notes (comma separated)</label>
              <input name="flavor" value={form.flavor} onChange={handleChange} className="input" placeholder="floral, earthy, sweet" />
            </div>
            <div className="col-span-2">
              <label className="text-xs font-medium text-gray-600 mb-1 block">Tags (comma separated)</label>
              <input name="tags" value={form.tags} onChange={handleChange} className="input" placeholder="premium, bestseller" />
            </div>
            <div className="col-span-2">
              <label className="flex items-center gap-2 cursor-pointer">
                <input type="checkbox" name="isFeatured" checked={form.isFeatured} onChange={handleChange} className="w-4 h-4 text-tea-600" />
                <span className="text-sm text-gray-700">Featured product</span>
              </label>
            </div>
          </div>
          <div className="flex gap-3 justify-end pt-2">
            <button type="button" onClick={onClose} className="btn-secondary">Cancel</button>
            <button type="submit" disabled={saving} className="btn-primary">{saving ? 'Saving...' : 'Save Product'}</button>
          </div>
        </form>
      </div>
    </div>
  );
};

const AdminProducts = () => {
  const [products, setProducts] = useState([]);
  const [pagination, setPagination] = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // null | 'create' | product object
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const params = { page, limit: 15, ...(search && { search }) };
      const { data } = await productAPI.getAll(params);
      setProducts(data.data);
      setPagination(data.pagination);
    } catch {
      toast.error('Failed to load products');
    } finally {
      setLoading(false);
    }
  }, [page, search]);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Deactivate "${name}"?`)) return;
    try {
      await productAPI.delete(id);
      toast.success('Product deactivated');
      fetchProducts();
    } catch {
      toast.error('Failed to deactivate');
    }
  };

  const handleSave = () => { setModal(null); fetchProducts(); };

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <div className="flex items-center justify-between mb-6">
        <h1 className="font-display text-2xl text-tea-900">Products</h1>
        <button onClick={() => setModal('create')} className="btn-primary flex items-center gap-2 text-sm">
          <AddIcon fontSize="small" /> Add Product
        </button>
      </div>

      <div className="mb-5">
        <input value={search} onChange={(e) => { setSearch(e.target.value); setPage(1); }} placeholder="Search products..." className="input w-72" />
      </div>

      {loading ? (
        <div className="grid grid-cols-1 gap-3">{[...Array(5)].map((_, i) => <div key={i} className="h-20 bg-tea-100 rounded-xl animate-pulse" />)}</div>
      ) : (
        <>
          <div className="card overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-tea-50 border-b border-tea-100">
                  <tr>
                    <th className="text-left px-4 py-3 font-medium text-gray-600">Product</th>
                    <th className="text-left px-4 py-3 font-medium text-gray-600">Category</th>
                    <th className="text-left px-4 py-3 font-medium text-gray-600">Price</th>
                    <th className="text-left px-4 py-3 font-medium text-gray-600">Variants</th>
                    <th className="text-left px-4 py-3 font-medium text-gray-600">Rating</th>
                    <th className="text-left px-4 py-3 font-medium text-gray-600">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-tea-50">
                  {products.map((p) => (
                    <tr key={p._id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-3">
                          <img src={p.thumbnail} alt={p.name} className="w-10 h-10 rounded-lg object-cover flex-shrink-0 bg-tea-100" onError={(e) => { e.target.src = 'https://images.unsplash.com/photo-1556679343-c7306c1976bc?w=40'; }} />
                          <div>
                            <p className="font-medium text-gray-800">{p.name}</p>
                            {p.isFeatured && <span className="badge bg-tea-100 text-tea-600 text-xs">Featured</span>}
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-gray-600 capitalize">{p.category.replace('-', ' ')}</td>
                      <td className="px-4 py-3 font-semibold text-gray-800">${p.basePrice.toFixed(2)}</td>
                      <td className="px-4 py-3 text-gray-600">{p.variants?.length || 0} variants</td>
                      <td className="px-4 py-3">
                        <span className="text-amber-500 font-medium">{p.rating > 0 ? `★ ${p.rating}` : '—'}</span>
                      </td>
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <button onClick={() => setModal(p)} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg transition-colors">
                            <EditIcon fontSize="small" />
                          </button>
                          <button onClick={() => handleDelete(p._id, p.name)} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                            <DeleteIcon fontSize="small" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {products.length === 0 && <div className="text-center py-10 text-gray-400 text-sm">No products found.</div>}
            </div>
          </div>
          <Pagination pagination={pagination} onPageChange={setPage} />
        </>
      )}

      {modal && (
        <ProductFormModal
          product={modal === 'create' ? null : modal}
          onClose={() => setModal(null)}
          onSave={handleSave}
        />
      )}
    </div>
  );
};

export default AdminProducts;
